<template>
  <div class="detail-container">
    <div class="navbar">
      <div class="nav-left" @click="goBack"><i class="ri-arrow-left-s-line"></i></div>
      <div class="nav-title">医案详情</div>
      <div class="nav-right"></div>
    </div>
    
    <div class="content" v-if="record">
      <!-- 舌诊/面诊 图片展示 -->
      <div class="image-card" v-if="record.imageUrl">
        <image :src="record.imageUrl" mode="aspectFit" class="diag-image"></image>
      </div>
      
      <!-- 诊断信息 -->
      <div class="info-card">
        <div class="card-title">
          <i class="ri-file-list-3-line"></i> 诊断结果
        </div>
        <div class="card-content">
          <div v-if="record.type === 'tongue'">
            <div class="item"><span class="label">舌质：</span>{{ diagnosisData.tongueBody }}</div>
            <div class="item"><span class="label">舌苔：</span>{{ diagnosisData.tongueCoating }}</div>
            <div class="item"><span class="label">辨证：</span>{{ diagnosisData.diagnosis }}</div>
          </div>
          <div v-else-if="record.type === 'face'">
             <div class="item"><span class="label">面色：</span>{{ diagnosisData.faceColor }}</div>
             <div class="item"><span class="label">光泽：</span>{{ diagnosisData.gloss }}</div>
             <div class="item"><span class="label">神态：</span>{{ diagnosisData.spirit }}</div>
             <div class="item"><span class="label">诊断：</span>{{ diagnosisData.diagnosis }}</div>
             <div class="item desc"><span class="label">描述：</span>{{ diagnosisData.diagnosisDesc }}</div>
          </div>
          <div v-else-if="record.type === 'chat'">
             <div class="item"><span class="label">摘要：</span>{{ diagnosisData.diagnosis }}</div>
             <div class="tags" v-if="diagnosisData.tags && diagnosisData.tags.length">
               <span class="tag" v-for="(tag, idx) in diagnosisData.tags" :key="idx">{{ tag }}</span>
             </div>
          </div>
        </div>
      </div>
      
      <!-- 建议 -->
      <div class="info-card" v-if="diagnosisData.advice">
        <div class="card-title">
          <i class="ri-heart-pulse-line"></i> 调理建议
        </div>
        <div class="card-content advice-text">
          {{ diagnosisData.advice }}
        </div>
      </div>
      
      <div class="time-info">
        记录时间：{{ formatTime(record.createdAt) }}
      </div>
    </div>
    
    <div class="loading" v-else>
      加载中...
    </div>
  </div>
</template>

<script>
import { getHistoryDetail } from '@/api/history.js';

export default {
  data() {
    return {
      record: null,
      diagnosisData: {}
    }
  },
  onLoad(options) {
    if (options.id) {
      this.fetchDetail(options.id);
    }
  },
  methods: {
    goBack() {
      uni.navigateBack();
    },
    fetchDetail(id) {
      getHistoryDetail(id).then(res => {
        if (res.code === '200') {
          this.record = res.data;
          if (this.record.diagnosisData) {
            this.diagnosisData = JSON.parse(this.record.diagnosisData);
          }
        }
      });
    },
    formatTime(timeStr) {
      if (!timeStr) return '';
      return timeStr.replace('T', ' ');
    }
  }
}
</script>

